368	/// Push a type-mismatch error for argument `arg`, stating `tname` was expected.
369	/// Always returns `Err`.
370	///
371	/// C: `LUALIB_API int luaL_typeerror(lua_State *L, int arg, const char *tname)`
372	pub fn type_error_arg(
373	    state: &mut LuaState,
374	    arg: i32,
375	    tname: &[u8],
376	) -> Result<usize, LuaError> {
377	    // C: if (luaL_getmetafield(L, arg, "__name") == LUA_TSTRING)
378	    //      typearg = lua_tostring(L, -1);
379	    //    else if (lua_type(L, arg) == LUA_TLIGHTUSERDATA)
380	    //      typearg = "light userdata";
381	    //    else
382	    //      typearg = luaL_typename(L, arg);
383	    let typearg: Vec<u8> = if get_metafield(state, arg, b"__name")? == LuaType::String {
384	        let bytes = state.peek_bytes(-1).unwrap_or_else(|| b"?".to_vec());
385	        state.pop_n(1);
386	        bytes
387	    } else if state.type_at(arg) == LuaType::LightUserData {
388	        b"light userdata".to_vec()
389	    } else {
390	        state.type_name_at(arg).to_vec()
391	    };
392	    // C: msg = lua_pushfstring(L, "%s expected, got %s", tname, typearg);
393	    // C: return luaL_argerror(L, arg, msg);
394	    let msg_owned = format!(
395	        "{} expected, got {}",
396	        BStr(tname),
397	        BStr(&typearg)
398	    );
399	    arg_error(state, arg, msg_owned.as_bytes())
400	}
