411	/// Push a string describing the location of the call at `level` onto the stack.
412	/// If no location is available, pushes an empty string.
413	///
414	/// C: `LUALIB_API void luaL_where(lua_State *L, int level)`
415	pub fn push_where(state: &mut LuaState, level: i32) -> Result<(), LuaError> {
416	    let mut ar = LuaDebug::default();
417	    if state.get_stack(level, &mut ar) {
418	        state.get_info(b"Sl", &mut ar)?;
419	        if ar.currentline > 0 {
420	            let src = ar.short_src.clone();
421	            let line = ar.currentline;
422	            state.push_fstring(format_args!("{}:{}: ", BStr(&src), line))?;
423	            return Ok(());
424	        }
425	    }
426	    // C: lua_pushfstring(L, "");  /* no information available */
427	    state.push_string(b"")?;
428	    Ok(())
429	}
