649	/// Return the string at `arg` as bytes; raise a type error if not a string.
650	///
651	/// C: `LUALIB_API const char *luaL_checklstring(lua_State *L, int arg, size_t *len)`
652	pub fn check_lstring(state: &mut LuaState, arg: i32) -> Result<GcRef<LuaString>, LuaError> {
653	    // C: const char *s = lua_tolstring(L, arg, len);
654	    match state.to_lua_string(arg) {
655	        Some(s) => Ok(s),
656	        None => {
