934	/// Find `needle` in `haystack`, returning the byte offset or `None`.
935	///
936	/// Internal helper replacing C's `strstr`.
937	fn find_bytes(haystack: &[u8], needle: &[u8]) -> Option<usize> {
938	    if needle.is_empty() {
939	        return Some(0);
940	    }
941	    haystack.windows(needle.len()).position(|w| w == needle)
942	}
