660	/// Constant-folding `luaK_posfix` for arithmetic binary operators where both
661	/// operands are already numeric literals (`KInt` / `KFlt`). Mirrors the
662	/// `constfolding` branch in C's `luaK_posfix`: when both operands are
663	/// numerals, the result is computed at compile time and stored back into
664	/// `e1`. Non-foldable arithmetic / bitwise binops fall through to the
665	/// two-register emit path (`OP_ADD` ... `OP_SHR`) plus an `OP_MMBIN`
666	/// metamethod-dispatch instruction. `Concat` is delegated to
667	/// `cg_emit_concat`; `Lt` to `cg_emit_order`; remaining logical and
668	/// comparison operators still hit `todo!()` so they surface as later
669	/// iterations' blockers.
670	fn cg_posfix_fold(
671	    fs: &mut FuncState,
672	    op: BinOpr,
673	    e1: &mut ExprDesc,
674	    e2: &mut ExprDesc,
675	    line: i32,
676	) -> Result<(), LuaError> {
677	    cg_discharge_vars(fs, line, e2)?;
678	
679	    let promote = |k: ExprKind, u: &ExprPayload| -> Option<f64> {
680	        match k {
681	            ExprKind::KInt => Some(u.ival as f64),
682	            ExprKind::KFlt => Some(u.nval),
683	            _ => None,
684	        }
685	    };
686	
687	    if let (ExprKind::KInt, ExprKind::KInt) = (e1.k, e2.k) {
688	        let a = e1.u.ival;
689	        let b = e2.u.ival;
690	        let r: Option<i64> = match op {
691	            BinOpr::Add => Some(a.wrapping_add(b)),
692	            BinOpr::Sub => Some(a.wrapping_sub(b)),
693	            BinOpr::Mul => Some(a.wrapping_mul(b)),
694	            BinOpr::Mod if b != 0 => Some(a.rem_euclid(b)),
695	            BinOpr::IDiv if b != 0 => Some(a.div_euclid(b)),
696	            BinOpr::BAnd => Some(a & b),
697	            BinOpr::BOr  => Some(a | b),
698	            BinOpr::BXor => Some(a ^ b),
699	            _ => None,
700	        };
701	        if let Some(v) = r {
702	            e1.k = ExprKind::KInt;
703	            e1.u.ival = v;
704	            return Ok(());
705	        }
706	    }
707	    if let (Some(a), Some(b)) = (promote(e1.k, &e1.u), promote(e2.k, &e2.u)) {
708	        let r: Option<f64> = match op {
709	            BinOpr::Add => Some(a + b),
710	            BinOpr::Sub => Some(a - b),
711	            BinOpr::Mul => Some(a * b),
712	            BinOpr::Div => Some(a / b),
713	            BinOpr::Pow => Some(a.powf(b)),
714	            _ => None,
715	        };
716	        if let Some(v) = r {
717	            if v.is_finite() {
718	                e1.k = ExprKind::KFlt;
719	                e1.u.nval = v;
720	                return Ok(());
721	            }
722	        }
723	    }
724	
725	    if matches!(op, BinOpr::Lt | BinOpr::Le) {
726	        return cg_emit_order(fs, op, e1, e2, line);
727	    }
728	
729	    if matches!(op, BinOpr::Gt | BinOpr::Ge) {
730	        let swap_op = if matches!(op, BinOpr::Gt) { BinOpr::Lt } else { BinOpr::Le };
731	        std::mem::swap(e1, e2);
732	        return cg_emit_order(fs, swap_op, e1, e2, line);
733	    }
734	
735	    if matches!(op, BinOpr::Eq | BinOpr::Ne) {
736	        return cg_emit_eq(fs, op, e1, e2, line);
737	    }
738	
739	    if matches!(op, BinOpr::And) {
740	        debug_assert_eq!(e1.t, NO_JUMP);
741	        cg_concat(fs, &mut e2.f, e1.f)?;
742	        *e1 = e2.clone();
743	        return Ok(());
744	    }
745	
746	    if matches!(op, BinOpr::Or) {
747	        debug_assert_eq!(e1.f, NO_JUMP);
748	        cg_concat(fs, &mut e2.t, e1.t)?;
749	        *e1 = e2.clone();
750	        return Ok(());
751	    }
752	
753	    if matches!(op, BinOpr::Concat) {
754	        return cg_emit_concat(fs, e1, e2, line);
755	    }
756	
757	    let (opcode, event) = match op {
758	        BinOpr::Add  => (lua_code::opcodes::OpCode::Add,  lua_types::tagmethod::TagMethod::Add),
759	        BinOpr::Sub  => (lua_code::opcodes::OpCode::Sub,  lua_types::tagmethod::TagMethod::Sub),
760	        BinOpr::Mul  => (lua_code::opcodes::OpCode::Mul,  lua_types::tagmethod::TagMethod::Mul),
761	        BinOpr::Mod  => (lua_code::opcodes::OpCode::Mod,  lua_types::tagmethod::TagMethod::Mod),
762	        BinOpr::Pow  => (lua_code::opcodes::OpCode::Pow,  lua_types::tagmethod::TagMethod::Pow),
763	        BinOpr::Div  => (lua_code::opcodes::OpCode::Div,  lua_types::tagmethod::TagMethod::Div),
764	        BinOpr::IDiv => (lua_code::opcodes::OpCode::IDiv, lua_types::tagmethod::TagMethod::Idiv),
765	        BinOpr::BAnd => (lua_code::opcodes::OpCode::BAnd, lua_types::tagmethod::TagMethod::Band),
