804	/// otherwise both operands are discharged to registers and the register
805	/// form (`OP_LT`) is emitted.
806	fn cg_emit_order(
807	    fs: &mut FuncState,
808	    op: BinOpr,
809	    e1: &mut ExprDesc,
810	    e2: &mut ExprDesc,
811	    line: i32,
812	) -> Result<(), LuaError> {
